public function saveInternalMarksheet(Request $request)
{

// return back();

    $input = $request->all();

    if (!isset($input['attendance'])) {
        return back()->with('error', 'No data provided');
    }
$subjectIds = [];

    foreach ($input['attendance'] as $subject_id => $attendance) {
    $subjectIds[] = $subject_id; // collect here

        // If marks field missing because disabled
        $marks = $input['internal'][$subject_id] ?? 0;

        // If absent set marks 0
        if ($attendance == 2) {
            $marks = NULL;
        }

        \App\Newinternalmark::updateOrInsert(
    [
        'exam_id' => $input['exam_id'],
        'candidate_id' => $input['candidate_id'],
        'subject_id' => $subject_id,
    ],
    [
        'approvedprogramme_id' => $input['approvedprogramme_id'],
        'internal' => $marks,
        'attendance' => $attendance,
        'user_id' => Auth::user()->id,
    ]
);

    }


if ($request->hasFile('marksheet_file')) {

    $file = $request->file('marksheet_file');
    $fname = time() . '_' . $file->getClientOriginalName();
    $file->move(public_path('files/internalmarksheets'), $fname);

$subjects = DB::table('subjects')
    ->whereIn('id', $subjectIds)
    ->select('subjecttype_id', 'syear')
    ->distinct()
    ->get();

foreach ($subjects as $sid) {

    \App\Internalmarksheet::create([
        'exam_id' => $input['exam_id'],
        'term' => $sid->syear ?? null,
        'subjecttype_id' => $sid->subjecttype_id ?? null,
        'approvedprogramme_id' => $input['approvedprogramme_id'],
        'filename' => $fname
    ]);

     \App\Attendance::create([
                    'candidate_id'=>$input['candidate_id'],
                    'exam_id'=>$input['exam_id'],
                    'exemption'=>'0',
                    'document_t'=>$fname,
                    'document_p'=>$fname,
                    'term'=>$sid->syear ?? null,
                    'attendance_p'=>$request->attendance_t,
                    'attendance_t'=>$request->attendance_t,

                    ]);
}

   
}



                    Session::flash('messages','Updated');

    return back();
}
